-- ============================================================================
-- Quiz Seed: 1 Corinthians — Part 2 (Chapters 9–16)
-- 3 difficulties × 8 chapters = 128 total questions
--   kids:   3 per chapter  = 24
--   teens:  5 per chapter  = 40
--   adults: 8 per chapter  = 64
-- ============================================================================

-- ═══════════════ CHAPTERS 9–12 ═══════════════

-- ═══ 1 Corinthians Chapter 9 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Corinthians', 9, 'kids', 1, 'Was Paul an apostle who had seen the Lord Jesus?', 'Yes, he had seen Jesus the Lord and was a true apostle', 'No, he had never seen Jesus', 'He was not sure', 'Only Peter had seen Jesus', 'a', '1 Corinthians 9:1 — "Am I not an apostle? am I not free? have I not seen Jesus Christ our Lord?"'),
('1 Corinthians', 9, 'kids', 2, 'Did Paul take money for preaching the gospel?', 'No, he preached for free even though he had the right to be paid', 'Yes, he charged a high price', 'He only accepted gold', 'He refused to preach at all', 'a', '1 Corinthians 9:18 — "What is my reward then? Verily that, when I preach the gospel, I may make the gospel of Christ without charge."'),
('1 Corinthians', 9, 'kids', 3, 'What does Paul compare the Christian life to?', 'A race — we should run to win the prize', 'A nap — we should rest and relax', 'A party — we should celebrate every day', 'A holiday — we should take it easy', 'a', '1 Corinthians 9:24 — "Know ye not that they which run in a race run all, but one receiveth the prize? So run, that ye may obtain."'),
-- Teens
('1 Corinthians', 9, 'teens', 1, 'What rights does Paul say he had as an apostle but chose not to use?', 'The right to eat and drink, to have a believing wife, and to receive financial support from the churches', 'The right to rule over cities', 'The right to command armies', 'The right to own large estates', 'a', '1 Corinthians 9:4-6 — "Have we not power to eat and to drink? Have we not power to lead about a sister, a wife, as well as other apostles... Or I only and Barnabas, have not we power to forbear working?"'),
('1 Corinthians', 9, 'teens', 2, 'What Old Testament principle does Paul quote about paying workers?', '"Thou shalt not muzzle the mouth of the ox that treadeth out the corn" — meaning workers deserve payment', 'Workers should never be paid', 'Only priests deserve wages', 'Oxen are more important than people', 'a', '1 Corinthians 9:9 — "For it is written in the law of Moses, Thou shalt not muzzle the mouth of the ox that treadeth out the corn. Doth God take care for oxen?"'),
('1 Corinthians', 9, 'teens', 3, 'What did Paul become to win different kinds of people?', 'All things to all men, that he might by all means save some', 'A wealthy merchant', 'A Roman soldier', 'A Greek philosopher', 'a', '1 Corinthians 9:22 — "I am made all things to all men, that I might by all means save some."'),
('1 Corinthians', 9, 'teens', 4, 'What kind of crown do athletes compete for versus what believers receive?', 'Athletes compete for a corruptible (perishable) crown, but believers for an incorruptible (imperishable) one', 'Both crowns are the same', 'Athletes get a better crown', 'Neither group receives a crown', 'a', '1 Corinthians 9:25 — "And every man that striveth for the mastery is temperate in all things. Now they do it to obtain a corruptible crown; but we an incorruptible."'),
('1 Corinthians', 9, 'teens', 5, 'What does Paul say he does to his own body?', 'He keeps it under subjection (disciplines it) lest after preaching to others he himself should be a castaway', 'He lets it do whatever it wants', 'He ignores his physical health', 'He pampers it constantly', 'a', '1 Corinthians 9:27 — "But I keep under my body, and bring it into subjection: lest that by any means, when I have preached to others, I myself should be a castaway."'),
-- Adults
('1 Corinthians', 9, 'adults', 1, 'How does chapter 9 function within the larger argument of chapters 8-10?', 'Paul offers himself as a living example of the principle he taught in chapter 8 — he voluntarily surrenders his legitimate apostolic rights for the sake of others, modelling the love-governed liberty he demands of the Corinthians', 'It is an unrelated digression', 'It introduces a completely new topic', 'It contradicts chapter 8', 'a', 'Chapter 9 is Paul''s autobiography of self-denial: he had the right to financial support (vv.4-14) but waived it (vv.15-18), adapting to different audiences (vv.19-23), and disciplining himself (vv.24-27) — all illustrating the voluntary surrender of rights for others.'),
('1 Corinthians', 9, 'adults', 2, 'What multiple arguments does Paul marshal to prove apostles deserve financial support?', 'Human analogy (soldiers, vinedressers, shepherds), Mosaic law (ox muzzle — Deut 25:4), temple practice (priests eat of the altar), and dominical command (the Lord ordained that preachers live of the gospel)', 'Only one argument from common sense', 'No arguments — he says they do not deserve support', 'Only a single Old Testament verse', 'a', '1 Corinthians 9:7-14 — Paul piles up evidence: secular analogies (v.7), Mosaic law (v.9), temple practice (v.13), and Jesus'' own command (v.14 — cf. Luke 10:7) to establish an irrefutable case for ministerial support.'),
('1 Corinthians', 9, 'adults', 3, 'What does Paul mean by "I am made all things to all men"?', 'He contextualised his approach — becoming as a Jew to Jews, as under the law to those under the law, as without law to Gentiles, and as weak to the weak — adapting culturally without compromising the gospel', 'He changed his beliefs constantly', 'He was a people-pleaser without conviction', 'He had no personal identity', 'a', '1 Corinthians 9:19-22 — Paul adapted his cultural practices and personal freedom to remove unnecessary barriers to the gospel, while remaining "under the law to Christ" (ennomos Christou) — bound to Christ''s own law.'),
('1 Corinthians', 9, 'adults', 4, 'What is the significance of Paul''s reference to the Isthmian Games?', 'Corinth hosted the biennial Isthmian Games — Paul uses athletic imagery the Corinthians would viscerally understand: discipline, self-control, and purposeful effort toward an eternal prize', 'Paul was a professional athlete', 'The games were held in Jerusalem', 'Paul is discussing the Olympics', 'a', '1 Corinthians 9:24-25 — The Isthmian Games were held near Corinth every two years. Victors received a wreath of withered celery (corruptible crown), making Paul''s contrast with the incorruptible crown vivid for his audience.'),
('1 Corinthians', 9, 'adults', 5, 'What does "castaway" (adokimos) mean in verse 27?', 'Disqualified — the term means failing to meet the standard of approval; Paul fears being rejected from reward or service, not losing salvation, after having preached to others', 'Shipwrecked at sea', 'Thrown into prison', 'Cast into hell', 'a', '1 Corinthians 9:27 — "Lest... I myself should be a castaway (adokimos)." The word means "unapproved" or "disqualified" — like an athlete who breaks training rules and is disqualified from receiving the prize, though they still exist.'),
('1 Corinthians', 9, 'adults', 6, 'How does Paul''s statement "necessity is laid upon me; yea, woe is unto me, if I preach not the gospel" reflect his understanding of calling?', 'Preaching is not a voluntary choice but a divine compulsion — Paul was commissioned by Christ on the Damascus road and cannot boast in what he is obligated to do', 'He wishes he could stop preaching', 'He preaches only for money', 'He considers preaching optional', 'a', '1 Corinthians 9:16 — "For though I preach the gospel, I have nothing to glory of: for necessity is laid upon me; yea, woe is unto me, if I preach not the gospel!"'),
('1 Corinthians', 9, 'adults', 7, 'What reward does Paul seek since he preaches under divine compulsion?', 'Making the gospel free of charge — his reward is the voluntary element: choosing not to use his right to financial support, so no one can accuse him of self-interest', 'A large salary', 'Public recognition', 'A position of political authority', 'a', '1 Corinthians 9:17-18 — "For if I do this thing willingly, I have a reward... What is my reward then? Verily that, when I preach the gospel, I may make the gospel of Christ without charge, that I abuse not my power in the gospel."'),
('1 Corinthians', 9, 'adults', 8, 'What does "under the law to Christ" (ennomos Christou) reveal about Paul''s relationship to law?', 'Paul is not lawless (anomos) but operates under a higher law — Christ''s law — which fulfils and transcends the Mosaic code; he is free from Moses but bound to Christ', 'Paul kept all 613 Mosaic commandments', 'Paul rejected all moral standards', 'Paul created his own legal code', 'a', '1 Corinthians 9:21 — "To them that are without law, as without law, (being not without law to God, but under the law to Christ)." Ennomos Christou indicates that Christ''s authoritative teaching governs Paul''s conduct.');

-- ═══ 1 Corinthians Chapter 10 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Corinthians', 10, 'kids', 1, 'What happened to the Israelites even though they all went through the Red Sea?', 'Many of them sinned and God was not pleased — they fell in the wilderness', 'They all made it safely to the promised land', 'They all obeyed God perfectly', 'Nothing bad happened to them', 'a', '1 Corinthians 10:5 — "But with many of them God was not well pleased: for they were overthrown in the wilderness."'),
('1 Corinthians', 10, 'kids', 2, 'Will God let you be tempted more than you can bear?', 'No, God is faithful and will not let you be tempted beyond what you can handle — He will provide a way of escape', 'Yes, sometimes temptation is too strong', 'God does not care about our temptations', 'We must fight temptation alone', 'a', '1 Corinthians 10:13 — "God is faithful, who will not suffer you to be tempted above that ye are able; but will with the temptation also make a way to escape, that ye may be able to bear it."'),
('1 Corinthians', 10, 'kids', 3, 'Should we do everything just for ourselves?', 'No, we should think about what helps other people, not just ourselves', 'Yes, always put yourself first', 'Only think about yourself', 'Nobody else matters', 'a', '1 Corinthians 10:24 — "Let no man seek his own, but every man another''s wealth."'),
-- Teens
('1 Corinthians', 10, 'teens', 1, 'Why does Paul bring up the story of Israel in the wilderness?', 'As warnings (examples) for believers — so we do not fall into the same sins of idolatry, fornication, tempting God, and murmuring', 'To teach a history lesson', 'To praise Israel''s faithfulness', 'To discuss geography', 'a', '1 Corinthians 10:6,11 — "Now these things were our examples, to the intent we should not lust after evil things, as they also lusted... Now all these things happened unto them for ensamples: and they are written for our admonition."'),
('1 Corinthians', 10, 'teens', 2, 'What warning does Paul give to those who think they are standing firm?', '"Let him that thinketh he standeth take heed lest he fall"', '"Keep standing no matter what"', '"Only the strong survive"', '"Your faith is unshakeable"', 'a', '1 Corinthians 10:12 — "Wherefore let him that thinketh he standeth take heed lest he fall."'),
('1 Corinthians', 10, 'teens', 3, 'Can a believer drink the cup of the Lord and the cup of devils?', 'No — you cannot be partakers of the Lord''s table and the table of devils', 'Yes, both are acceptable', 'Only in special circumstances', 'It depends on your intentions', 'a', '1 Corinthians 10:21 — "Ye cannot drink the cup of the Lord, and the cup of devils: ye cannot be partakers of the Lord''s table, and of the table of devils."'),
('1 Corinthians', 10, 'teens', 4, 'What principle does Paul give for making decisions about food and other matters?', '"Whether therefore ye eat, or drink, or whatsoever ye do, do all to the glory of God"', '"Eat whatever makes you happy"', '"Follow the majority''s opinion"', '"Do what is easiest"', 'a', '1 Corinthians 10:31 — "Whether therefore ye eat, or drink, or whatsoever ye do, do all to the glory of God."'),
('1 Corinthians', 10, 'teens', 5, 'What practical instruction does Paul give about meat sold in the market?', 'Eat whatever is sold in the market without asking questions for conscience'' sake — the earth is the Lord''s', 'Never eat meat from the market', 'Only buy kosher meat', 'Always interrogate the seller', 'a', '1 Corinthians 10:25-26 — "Whatsoever is sold in the shambles, that eat, asking no question for conscience sake: For the earth is the Lord''s, and the fulness thereof."'),
-- Adults
('1 Corinthians', 10, 'adults', 1, 'What typological reading does Paul give to Israel''s wilderness experiences?', 'The cloud and sea represent baptism, the manna and water represent spiritual food and drink, and the rock that followed them was Christ — all prefiguring Christian sacraments', 'They are merely historical records', 'They have no connection to Christianity', 'They are allegorical fiction', 'a', '1 Corinthians 10:1-4 — "All baptized unto Moses in the cloud and in the sea; And did all eat the same spiritual meat; And did all drink the same spiritual drink: for they drank of that spiritual Rock that followed them: and that Rock was Christ."'),
('1 Corinthians', 10, 'adults', 2, 'What does Paul mean by identifying the rock as Christ?', 'A typological identification — the rock that provided water in the wilderness (Exodus 17, Numbers 20) was a type of Christ, the true source of spiritual sustenance; the rabbinic tradition of a "following rock" is reinterpreted christologically', 'Christ was literally a physical rock', 'The rock had no spiritual meaning', 'Paul was confused about Old Testament history', 'a', '1 Corinthians 10:4 — "That Rock was Christ." Paul draws on both Exodus 17:6 and Numbers 20:11, and possibly the Jewish tradition of a mobile well, reinterpreting the entire wilderness provision as Christ''s work.'),
('1 Corinthians', 10, 'adults', 3, 'How does 1 Corinthians 10:13 function theologically?', 'It guarantees God''s covenant faithfulness in temptation — no trial exceeds God''s grace, and He always provides an exit strategy; this is a promise of divine provision, not human self-sufficiency', 'It is a generic motivational saying', 'It promises that believers will never face temptation', 'It applies only to apostles', 'a', '1 Corinthians 10:13 — "God is faithful, who will not suffer you to be tempted above that ye are able; but will with the temptation also make a way to escape, that ye may be able to bear it." The emphasis is on God''s faithfulness, not human willpower.'),
('1 Corinthians', 10, 'adults', 4, 'What does Paul argue about the relationship between the Lord''s Supper and pagan sacrifices?', 'The cup of blessing and bread create communion (koinōnia) with Christ''s body and blood — just as pagan sacrifices create fellowship with demons; therefore participation in both is mutually exclusive', 'There is no connection between them', 'Both are equally valid forms of worship', 'The Lord''s Supper replaced all other rituals', 'a', '1 Corinthians 10:16,20-21 — "The cup of blessing which we bless, is it not the communion of the blood of Christ?... the things which the Gentiles sacrifice, they sacrifice to devils, and not to God... Ye cannot drink the cup of the Lord, and the cup of devils."'),
('1 Corinthians', 10, 'adults', 5, 'What does Paul mean by "Do we provoke the Lord to jealousy? are we stronger than he?"', 'Participating in idol worship provokes God''s jealousy (echoing Deuteronomy 32:21) — the rhetorical question warns that no one is strong enough to survive divine judgment for spiritual unfaithfulness', 'God cannot be provoked', 'Believers are indeed stronger than God', 'Jealousy does not apply to God', 'a', '1 Corinthians 10:22 — "Do we provoke the Lord to jealousy? are we stronger than he?" Paul echoes the Song of Moses (Deuteronomy 32:21) where Israel provoked God to jealousy through idolatry.'),
('1 Corinthians', 10, 'adults', 6, 'How does Paul resolve the practical question of meat in the marketplace?', 'Buy and eat freely without investigating its origin — the earth is the Lord''s (Psalm 24:1); but if someone specifically identifies it as idol-offered, abstain for the sake of the informant''s conscience, not your own', 'Always investigate the origin of every food item', 'Never eat marketplace meat', 'Only eat food prepared at home', 'a', '1 Corinthians 10:25-28 — Paul gives a nuanced three-scenario answer: (1) buy freely (v.25), (2) eat freely at a pagan''s dinner (v.27), (3) abstain if told it''s idol-offered (v.28) — always for the other person''s conscience.'),
('1 Corinthians', 10, 'adults', 7, 'What overarching ethical principle does Paul establish for all conduct?', '"Do all to the glory of God" — every action, including mundane activities like eating and drinking, should be directed toward glorifying God, forming the supreme criterion for Christian ethics', 'Follow the majority opinion', 'Do whatever feels right', 'Follow Roman customs', 'a', '1 Corinthians 10:31 — "Whether therefore ye eat, or drink, or whatsoever ye do, do all to the glory of God." This verse provides the teleological framework for all ethical decisions in Paul''s thought.'),
('1 Corinthians', 10, 'adults', 8, 'How does Paul summarise his approach at the chapter''s conclusion?', '"Even as I please all men in all things, not seeking mine own profit, but the profit of many, that they may be saved" — modelling the self-denying love that limits liberty for others'' salvation', 'He seeks his own comfort first', 'He focuses on personal gain', 'He ignores the needs of others', 'a', '1 Corinthians 10:33 — "Even as I please all men in all things, not seeking mine own profit, but the profit of many, that they may be saved." This summarises Paul''s missional ethic of voluntary self-limitation.');

-- ═══ 1 Corinthians Chapter 11 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Corinthians', 11, 'kids', 1, 'What special meal did Jesus share with His disciples that Paul writes about?', 'The Lord''s Supper — with bread and the cup', 'A birthday party', 'A regular breakfast', 'A fishing picnic', 'a', '1 Corinthians 11:23-24 — "The Lord Jesus the same night in which he was betrayed took bread: And when he had given thanks, he brake it."'),
('1 Corinthians', 11, 'kids', 2, 'What does the bread represent in the Lord''s Supper?', 'The body of Jesus, which was broken for us', 'Just ordinary food', 'The temple building', 'A gift from heaven', 'a', '1 Corinthians 11:24 — "Take, eat: this is my body, which is broken for you: this do in remembrance of me."'),
('1 Corinthians', 11, 'kids', 3, 'What does the cup represent?', 'The new testament (covenant) in Jesus'' blood', 'Just grape juice', 'Water from a well', 'Rain from the sky', 'a', '1 Corinthians 11:25 — "This cup is the new testament in my blood: this do ye, as oft as ye drink it, in remembrance of me."'),
-- Teens
('1 Corinthians', 11, 'teens', 1, 'What problem was happening when the Corinthians gathered for the Lord''s Supper?', 'Some were eating all the food and getting drunk while others went hungry — they were not discerning the body of the Lord', 'They forgot to bring food', 'They came at different times by accident', 'The food was spoiled', 'a', '1 Corinthians 11:21 — "For in eating every one taketh before other his own supper: and one is hungry, and another is drunken."'),
('1 Corinthians', 11, 'teens', 2, 'What does Paul say about eating the bread and drinking the cup unworthily?', 'He who eats and drinks unworthily is guilty of the body and blood of the Lord', 'It makes no difference how you approach it', 'Only the pastor can eat unworthily', 'Unworthiness does not apply to believers', 'a', '1 Corinthians 11:27 — "Wherefore whosoever shall eat this bread, and drink this cup of the Lord, unworthily, shall be guilty of the body and blood of the Lord."'),
('1 Corinthians', 11, 'teens', 3, 'What should a person do before eating the Lord''s Supper?', 'Examine himself — let a man examine himself and so let him eat', 'Just eat as quickly as possible', 'Let someone else examine him', 'Wait until everyone is perfect', 'a', '1 Corinthians 11:28 — "But let a man examine himself, and so let him eat of that bread, and drink of that cup."'),
('1 Corinthians', 11, 'teens', 4, 'What consequences did some Corinthians experience because of their unworthy approach?', 'Many were weak and sickly, and many had died ("sleep")', 'They became wealthier', 'They received extra spiritual gifts', 'Nothing happened to them', 'a', '1 Corinthians 11:30 — "For this cause many are weak and sickly among you, and many sleep."'),
('1 Corinthians', 11, 'teens', 5, 'What did Paul tell the Corinthians to do when they come together to eat?', 'Wait for one another — tarry one for another', 'Start eating as soon as you arrive', 'Eat at home and skip the church meal', 'Only the leaders should eat', 'a', '1 Corinthians 11:33 — "Wherefore, my brethren, when ye come together to eat, tarry one for another."'),
-- Adults
('1 Corinthians', 11, 'adults', 1, 'What is the order of headship Paul presents and what does "head" mean in context?', 'God is the head of Christ, Christ is the head of every man, and the man is the head of the woman — "head" (kephalē) likely denotes source/authority, establishing a relational order without implying inferiority', 'Women are inferior to men', 'There is no order at all', 'Only God has headship', 'a', '1 Corinthians 11:3 — "But I would have you know, that the head of every man is Christ; and the head of the woman is the man; and the head of Christ is God." The Son is not inferior to the Father despite being "headed" by Him, showing headship is relational, not about worth.'),
('1 Corinthians', 11, 'adults', 2, 'What is the earliest written account of the Lord''s Supper institution, and why is it significant?', 'Paul''s account here (written c. AD 55) predates the Gospel accounts — he received it "of the Lord" (direct revelation or authoritative tradition traceable to Jesus), making it the oldest record of the institution', 'Matthew''s account is earlier', 'Luke wrote first', 'The Didache recorded it first', 'a', '1 Corinthians 11:23 — "For I have received of the Lord that which also I delivered unto you." Written around AD 55, this predates Mark (c. AD 65) and is the earliest extant written account of the Lord''s Supper institution.'),
('1 Corinthians', 11, 'adults', 3, 'What does "not discerning the Lord''s body" mean in verse 29?', 'Failing to recognise both the sacred significance of the elements (Christ''s sacrificial body) and the corporate reality of the church as Christ''s body — treating the Supper as a common meal while despising fellow believers', 'Failing to see a physical transformation of the bread', 'Not understanding nutrition', 'Not knowing the recipe', 'a', '1 Corinthians 11:29 — "For he that eateth and drinketh unworthily, eateth and drinketh damnation to himself, not discerning the Lord''s body." The double referent (sacramental body and ecclesiastical body) fits the context of both communion and community abuse.'),
('1 Corinthians', 11, 'adults', 4, 'What does Paul mean by "when we are judged, we are chastened of the Lord, that we should not be condemned with the world"?', 'God''s temporal discipline of believers (sickness, death) is corrective, not condemnatory — it is fatherly chastening to prevent final condemnation alongside the unbelieving world', 'Believers can lose their salvation', 'God never disciplines believers', 'Discipline and condemnation are the same', 'a', '1 Corinthians 11:32 — "But when we are judged, we are chastened of the Lord, that we should not be condemned with the world." This distinguishes divine discipline (paideúō — parental training) from final judgment (katakrinō — condemnation).'),
('1 Corinthians', 11, 'adults', 5, 'How does Paul''s phrase "this do in remembrance of me" (anamnēsis) differ from mere recollection?', 'Anamnēsis is active re-presentation — not merely recalling a past event but making its reality present and effective in the assembly, proclaiming the Lord''s death until He comes', 'It is simple nostalgia', 'It has no theological significance', 'It means performing a magic ritual', 'a', '1 Corinthians 11:24-25 — "This do in remembrance of me." The Greek anamnēsis carries the Jewish Passover sense of active memorial — each celebration participates in and proclaims the redemptive event.'),
('1 Corinthians', 11, 'adults', 6, 'What does "ye do shew the Lord''s death till he come" reveal about the Lord''s Supper?', 'It is simultaneously backward-looking (proclamation of Christ''s death), present (communion with the living Lord), and forward-looking (anticipating His return) — a comprehensive eschatological act', 'It is only about the past', 'It has no future dimension', 'It is purely symbolic with no real significance', 'a', '1 Corinthians 11:26 — "For as often as ye eat this bread, and drink this cup, ye do shew the Lord''s death till he come." The three temporal dimensions make the Supper a microcosm of redemptive history.'),
('1 Corinthians', 11, 'adults', 7, 'What social abuse was occurring at the Corinthian Lord''s Supper?', 'Wealthy members were eating lavish private meals while poor members went hungry — creating class divisions that contradicted the unity symbolised by the one bread and one cup', 'The food was prepared incorrectly', 'The meeting place was too small', 'There was a shortage of bread', 'a', '1 Corinthians 11:21-22 — "For in eating every one taketh before other his own supper: and one is hungry, and another is drunken... despise ye the church of God, and shame them that have not?" The Corinthian agape feast had become a mirror of Roman social stratification.'),
('1 Corinthians', 11, 'adults', 8, 'What does "this cup is the new testament in my blood" establish theologically?', 'It inaugurates the new covenant prophesied in Jeremiah 31:31-34 — Christ''s blood ratifies a new covenant replacing the old Sinaitic covenant, providing forgiveness and internalized knowledge of God', 'It is a reference to the old covenant', 'It creates a third covenant alongside the old and new', 'It abolishes all covenants', 'a', '1 Corinthians 11:25 — "This cup is the new testament in my blood." The Greek diathēkē kainē echoes Jeremiah 31:31 (LXX), explicitly identifying the Lord''s Supper with the fulfilment of the new covenant promise.');

-- ═══ 1 Corinthians Chapter 12 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Corinthians', 12, 'kids', 1, 'Does every Christian get the same spiritual gift?', 'No, the Spirit gives different gifts to different people', 'Yes, everyone gets exactly the same gifts', 'No one gets any gifts', 'Only pastors receive gifts', 'a', '1 Corinthians 12:4 — "Now there are diversities of gifts, but the same Spirit."'),
('1 Corinthians', 12, 'kids', 2, 'What does Paul compare the church to?', 'A human body with many different parts that all work together', 'A building made of bricks', 'A garden full of flowers', 'A fleet of ships', 'a', '1 Corinthians 12:12 — "For as the body is one, and hath many members, and all the members of that one body, being many, are one body: so also is Christ."'),
('1 Corinthians', 12, 'kids', 3, 'Can any part of the body say it does not need the other parts?', 'No, the eye cannot say to the hand "I have no need of thee" — every part is needed', 'Yes, some parts are not needed', 'Only the head matters', 'The body can work with just one part', 'a', '1 Corinthians 12:21 — "And the eye cannot say unto the hand, I have no need of thee: nor again the head to the feet, I have no need of you."'),
-- Teens
('1 Corinthians', 12, 'teens', 1, 'What are some of the spiritual gifts Paul mentions?', 'Wisdom, knowledge, faith, healing, miracles, prophecy, discerning of spirits, tongues, interpretation of tongues', 'Only preaching and teaching', 'Only singing and music', 'Only giving money', 'a', '1 Corinthians 12:8-10 — Paul lists nine gifts: word of wisdom, word of knowledge, faith, gifts of healing, working of miracles, prophecy, discerning of spirits, divers kinds of tongues, and interpretation of tongues.'),
('1 Corinthians', 12, 'teens', 2, 'Who decides which gifts each person receives?', 'The Holy Spirit — dividing to every man severally as He will', 'Each person chooses their own gift', 'The church leaders assign gifts', 'Gifts are earned through hard work', 'a', '1 Corinthians 12:11 — "But all these worketh that one and the selfsame Spirit, dividing to every man severally as he will."'),
('1 Corinthians', 12, 'teens', 3, 'What does Paul say about the weaker or less honourable members of the body?', 'They are necessary — God gives more abundant honour to the parts that lack it, so there should be no division in the body', 'They are unimportant and can be removed', 'They should be hidden away', 'They have no function', 'a', '1 Corinthians 12:22-24 — "Nay, much more those members of the body, which seem to be more feeble, are necessary... God hath tempered the body together, having given more abundant honour to that part which lacked."'),
('1 Corinthians', 12, 'teens', 4, 'What happens when one member of the body suffers?', 'All the members suffer with it — and if one member is honoured, all the members rejoice with it', 'The other members are unaffected', 'Only nearby members feel it', 'The body ignores the suffering part', 'a', '1 Corinthians 12:26 — "And whether one member suffer, all the members suffer with it; or one member be honoured, all the members rejoice with it."'),
('1 Corinthians', 12, 'teens', 5, 'Does everyone have the same role in the church?', 'No — God set some as apostles, prophets, teachers, miracles, healings, helps, governments, tongues — not all have every gift', 'Yes, everyone has exactly the same role', 'Roles do not matter in the church', 'Only one gift is valid', 'a', '1 Corinthians 12:28-30 — "And God hath set some in the church, first apostles, secondarily prophets, thirdly teachers, after that miracles... Are all apostles? are all prophets? are all teachers?"'),
-- Adults
('1 Corinthians', 12, 'adults', 1, 'What Trinitarian structure does Paul present in verses 4-6?', 'Diversities of gifts but the same Spirit, diversities of administrations but the same Lord, diversities of operations but the same God — the Trinity is the source of all spiritual gifts, with each Person distinctly involved', 'Only the Spirit gives gifts', 'Only God the Father is mentioned', 'The Trinity is not referenced', 'a', '1 Corinthians 12:4-6 — "Now there are diversities of gifts, but the same Spirit. And there are differences of administrations, but the same Lord. And there are diversities of operations, but it is the same God which worketh all in all." Spirit, Lord (Son), and God (Father) are distinctly named.'),
('1 Corinthians', 12, 'adults', 2, 'What does "by one Spirit are we all baptized into one body" mean?', 'The Holy Spirit''s work at conversion incorporates every believer — whether Jew or Greek, bond or free — into the one body of Christ; this is Spirit baptism creating organic unity', 'It refers only to water baptism', 'It describes a second blessing experience', 'It applies only to the original apostles', 'a', '1 Corinthians 12:13 — "For by one Spirit are we all baptized into one body, whether we be Jews or Gentiles, whether we be bond or free; and have been all made to drink into one Spirit."'),
('1 Corinthians', 12, 'adults', 3, 'How does Paul''s body analogy counter both inferiority and superiority complexes in the church?', 'Against inferiority: the foot and ear are still part of the body even if they are not the hand or eye (vv.15-16). Against superiority: the eye cannot say to the hand "I have no need of thee" (v.21). Every member is essential and interdependent', 'Only superior members matter', 'Inferiority is a sign of weak faith', 'The body analogy is purely decorative', 'a', '1 Corinthians 12:15-21 — Paul addresses both the temptation of less prominent members to withdraw ("I am not of the body," v.16) and the temptation of prominent members to dismiss others ("I have no need of thee," v.21).'),
('1 Corinthians', 12, 'adults', 4, 'What does Paul mean by God "tempering the body together" and giving "more abundant honour to that part which lacked"?', 'God intentionally designed the church so that less visible and less esteemed members receive compensating honour, preventing schism and ensuring mutual care — divine design produces interdependence', 'God favours prominent members', 'Less honourable parts should be removed', 'The church is a hierarchy of value', 'a', '1 Corinthians 12:24-25 — "God hath tempered the body together, having given more abundant honour to that part which lacked: That there should be no schism in the body; but that the members should have the same care one for another."'),
('1 Corinthians', 12, 'adults', 5, 'What is the significance of Paul''s ranked list: "first apostles, secondarily prophets, thirdly teachers"?', 'It establishes a functional priority for foundational ministries — apostles and prophets lay the foundation (Ephesians 2:20), teachers build on it; this is a rank of function, not personal worth', 'It is a hierarchy of personal importance', 'Teachers are more important than apostles', 'The list is random with no order', 'a', '1 Corinthians 12:28 — "And God hath set some in the church, first apostles, secondarily prophets, thirdly teachers." The ordinal numbering (prōton, deuteron, triton) indicates intentional ranking of foundational roles.'),
('1 Corinthians', 12, 'adults', 6, 'What rhetorical effect do Paul''s seven rapid-fire questions in verses 29-30 produce?', 'Each expects a "no" answer (using mē in Greek), proving that no single gift is universal — directly countering the Corinthian elevation of tongues as the mark of true spirituality', 'They expect "yes" answers', 'They are open-ended discussion prompts', 'They have no expected answer', 'a', '1 Corinthians 12:29-30 — "Are all apostles? are all prophets?... do all speak with tongues? do all interpret?" The Greek particle mē expects negative answers, definitively ruling out any single gift as normative for all believers.'),
('1 Corinthians', 12, 'adults', 7, 'What does "covet earnestly the best gifts" mean, and how does it connect to chapter 13?', 'Paul urges them to desire the greater (more edifying) gifts — but then reveals a "more excellent way" (love) that transcends and governs all gifts; love is not itself a gift but the indispensable context for all gifts', 'They should compete for the most spectacular gifts', 'Love replaces all spiritual gifts', 'Gifts are unimportant', 'a', '1 Corinthians 12:31 — "But covet earnestly the best gifts: and yet shew I unto you a more excellent way." The "best gifts" are those that edify the body (prophecy over tongues — 14:1-5), but all are worthless without love (ch.13).'),
('1 Corinthians', 12, 'adults', 8, 'How does Paul''s phrase "Now ye are the body of Christ, and members in particular" define ecclesiology?', 'The church is not merely a human organisation but the actual body of Christ on earth — each individual believer is a particular, irreplaceable member with a God-assigned function in the organic whole', 'The church is merely a social club', 'Individual members have no significance', 'The body of Christ is only a metaphor with no real meaning', 'a', '1 Corinthians 12:27 — "Now ye are the body of Christ, and members in particular." The Greek melē ek merous means "members individually" — each person has a specific, divinely appointed role within the corporate body.');

-- ═══════════════ CHAPTERS 13–16 ═══════════════

-- ═══ 1 Corinthians Chapter 13 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Corinthians', 13, 'kids', 1, 'What is the most important thing according to this chapter?', 'Love (charity)', 'Being very smart', 'Being very strong', 'Being very rich', 'a', '1 Corinthians 13:13 — "And now abideth faith, hope, charity, these three; but the greatest of these is charity."'),
('1 Corinthians', 13, 'kids', 2, 'What does love (charity) do and not do?', 'Love is patient and kind — it does not envy or boast', 'Love is selfish and proud', 'Love is angry and jealous', 'Love is rude and mean', 'a', '1 Corinthians 13:4 — "Charity suffereth long, and is kind; charity envieth not; charity vaunteth not itself, is not puffed up."'),
('1 Corinthians', 13, 'kids', 3, 'Will love ever end?', 'No, love never fails — it lasts forever', 'Yes, love ends when you grow up', 'Love only lasts for a little while', 'Love stops when things get hard', 'a', '1 Corinthians 13:8 — "Charity never faileth."'),
-- Teens
('1 Corinthians', 13, 'teens', 1, 'What is Paul without love, even if he could speak in tongues of men and angels?', 'A sounding brass or a tinkling cymbal — just empty noise', 'A great speaker', 'A wonderful musician', 'An impressive person', 'a', '1 Corinthians 13:1 — "Though I speak with the tongues of men and of angels, and have not charity, I am become as sounding brass, or a tinkling cymbal."'),
('1 Corinthians', 13, 'teens', 2, 'Even if you have enough faith to move mountains, what are you without love?', 'Nothing — without charity, I am nothing', 'A great hero of faith', 'The most powerful person alive', 'Still very impressive', 'a', '1 Corinthians 13:2 — "And though I have all faith, so that I could remove mountains, and have not charity, I am nothing."'),
('1 Corinthians', 13, 'teens', 3, 'What does Paul compare our current understanding to?', 'Seeing through a glass darkly — we know in part now, but one day we will know fully', 'Perfect crystal-clear vision', 'Complete understanding of everything', 'We already know everything', 'a', '1 Corinthians 13:12 — "For now we see through a glass, darkly; but then face to face: now I know in part; but then shall I know even as also I am known."'),
('1 Corinthians', 13, 'teens', 4, 'What three things abide (remain) forever?', 'Faith, hope, and charity (love) — and the greatest is love', 'Gold, silver, and bronze', 'Prophecy, tongues, and knowledge', 'Power, wisdom, and strength', 'a', '1 Corinthians 13:13 — "And now abideth faith, hope, charity, these three; but the greatest of these is charity."'),
('1 Corinthians', 13, 'teens', 5, 'What does love not keep a record of?', 'Wrongs — love thinketh no evil and rejoiceth not in iniquity', 'Good deeds', 'Compliments', 'Gifts received', 'a', '1 Corinthians 13:5-6 — "Doth not behave itself unseemly, seeketh not her own, is not easily provoked, thinketh no evil; Rejoiceth not in iniquity, but rejoiceth in the truth."'),
-- Adults
('1 Corinthians', 13, 'adults', 1, 'How does chapter 13 function within the broader argument of chapters 12-14?', 'It is the theological hinge — chapter 12 establishes the diversity of gifts, chapter 13 establishes love as the governing principle for all gifts, and chapter 14 applies this to the specific issue of tongues vs. prophecy', 'It is an independent hymn unrelated to its context', 'It replaces the teaching on spiritual gifts', 'It is a later addition by another author', 'a', 'Chapter 13 is not a standalone poem but the strategic centre of Paul''s argument on spiritual gifts. It answers 12:31''s "more excellent way" and prepares for 14:1''s "Follow after charity, and desire spiritual gifts."'),
('1 Corinthians', 13, 'adults', 2, 'What does Paul''s list of love''s fifteen attributes reveal about the Corinthian problems?', 'Each attribute addresses a specific Corinthian failing — they were impatient, envious, boastful, puffed up, rude, self-seeking, easily provoked, keeping score, and rejoicing in others'' failures', 'The list is generic with no connection to Corinth', 'Paul is describing his own virtues', 'The list is borrowed from Greek philosophy', 'a', '1 Corinthians 13:4-7 — Each attribute mirrors a Corinthian vice: "envieth not" (they envied gifts), "vaunteth not itself" (they boasted), "is not puffed up" (they were arrogant — 4:6,18,19; 5:2; 8:1), "seeketh not her own" (they were selfish — 10:24,33).'),
('1 Corinthians', 13, 'adults', 3, 'What does "when that which is perfect is come" refer to?', 'Most likely the eschatological consummation — Christ''s return or the eternal state — when partial knowledge and gifts give way to complete, face-to-face knowledge of God', 'The completion of the New Testament canon', 'The maturity of the church', 'The destruction of Jerusalem in AD 70', 'a', '1 Corinthians 13:10,12 — "But when that which is perfect is come, then that which is in part shall be done away... then face to face." The "face to face" language echoes Numbers 12:8 and suggests direct encounter with God, best fitting the eschaton.'),
('1 Corinthians', 13, 'adults', 4, 'What is the significance of "I shall know even as also I am known"?', 'In the eschaton, believers will know God with the same directness and intimacy with which God now knows them — not omniscience, but relational, unmediated knowledge replacing the current partial and indirect knowing', 'Believers will become omniscient', 'This refers only to self-knowledge', 'Knowledge will be eliminated', 'a', '1 Corinthians 13:12 — "Then shall I know even as also I am known." The verb epiginōskō (full knowledge) contraces ginōskō (partial knowledge) — the asymmetry of God knowing us will be resolved by our full knowing of Him.'),
('1 Corinthians', 13, 'adults', 5, 'Why is love "the greatest" even above faith and hope?', 'Faith and hope are temporal — faith will give way to sight and hope to fulfillment — but love is eternal, reflecting the very nature of God who is love (1 John 4:8); love participates in God''s own character', 'Because Paul personally preferred love', 'Because faith and hope are unimportant', 'Because love is easier to practise', 'a', '1 Corinthians 13:13 — "The greatest of these is charity." Faith becomes sight (2 Corinthians 5:7) and hope becomes reality (Romans 8:24) at Christ''s return, but love endures because it is the essence of God''s own nature.'),
('1 Corinthians', 13, 'adults', 6, 'How does "love beareth all things, believeth all things, hopeth all things, endureth all things" work grammatically?', 'The four "all things" (panta) clauses form a chiasm (A-B-B''-A''): bearing/enduring frame the outer ring (patient endurance), while believing/hoping form the inner ring (positive trust) — love covers every dimension of human experience', 'The phrases are random with no structure', 'They are four separate commands', 'Each phrase contradicts the one before it', 'a', '1 Corinthians 13:7 — "Beareth all things, believeth all things, hopeth all things, endureth all things." The structure moves from passive endurance to active trust and back to endurance, creating a comprehensive portrait of love''s resilience.'),
('1 Corinthians', 13, 'adults', 7, 'What does Paul''s childhood metaphor ("When I was a child... when I became a man") illustrate?', 'The current exercise of partial gifts (tongues, prophecy, knowledge) is to the eschatological fullness as childhood is to adulthood — present spiritual experiences are real but immature compared to what is coming', 'Childhood is sinful and adulthood is righteous', 'Spiritual gifts are childish and should be abandoned now', 'Growing up means losing all spiritual experiences', 'a', '1 Corinthians 13:11 — "When I was a child, I spake as a child, I understood as a child, I thought as a child: but when I became a man, I put away childish things." The analogy legitimises present gifts while relativising them in light of future glory.'),
('1 Corinthians', 13, 'adults', 8, 'How does Paul''s claim that giving one''s body to be burned without love profits nothing challenge the Corinthian value system?', 'Even the most extreme act of self-sacrifice — martyrdom — is spiritually worthless without love, demolishing the idea that spectacular spiritual experiences or heroic acts can substitute for genuine Christ-like love', 'Martyrdom is always wrong', 'Physical sacrifice automatically equals spiritual merit', 'Paul discourages all forms of sacrifice', 'a', '1 Corinthians 13:3 — "And though I bestow all my goods to feed the poor, and though I give my body to be burned, and have not charity, it profiteth me nothing." The ultimate sacrifices of possessions and life itself are rendered meaningless without love.');

-- ═══ 1 Corinthians Chapter 14 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Corinthians', 14, 'kids', 1, 'Which is more helpful in church — speaking in tongues or prophecy?', 'Prophecy, because it speaks to people in a language they can understand and helps them', 'Tongues, because it sounds more impressive', 'Neither one matters', 'Both are equally helpful in every situation', 'a', '1 Corinthians 14:3-4 — "But he that prophesieth speaketh unto men to edification, and exhortation, and comfort. He that speaketh in an unknown tongue edifieth himself; but he that prophesieth edifieth the church."'),
('1 Corinthians', 14, 'kids', 2, 'Should church services be confusing or orderly?', 'Orderly — God is not the author of confusion, but of peace', 'Confusing is fine', 'It does not matter how services are run', 'The louder the better', 'a', '1 Corinthians 14:33 — "For God is not the author of confusion, but of peace, as in all churches of the saints."'),
('1 Corinthians', 14, 'kids', 3, 'What should everything in church be done for?', 'To build up and help others — let all things be done unto edifying', 'To make one person look important', 'To entertain the audience', 'To show off spiritual gifts', 'a', '1 Corinthians 14:26 — "Let all things be done unto edifying."'),
-- Teens
('1 Corinthians', 14, 'teens', 1, 'Why does Paul prefer prophecy over tongues in the gathered church?', 'Because prophecy edifies the whole church while uninterpreted tongues only edify the speaker', 'Because tongues are sinful', 'Because prophecy is louder', 'Because tongues are fake', 'a', '1 Corinthians 14:4-5 — "He that speaketh in an unknown tongue edifieth himself; but he that prophesieth edifieth the church. I would that ye all spake with tongues but rather that ye prophesied: for greater is he that prophesieth than he that speaketh with tongues, except he interpret."'),
('1 Corinthians', 14, 'teens', 2, 'What does Paul say about speaking in tongues without an interpreter?', 'The speaker should keep silent in the church and speak to himself and to God', 'He should speak as loudly as possible', 'The church must listen anyway', 'An interpreter is never needed', 'a', '1 Corinthians 14:28 — "But if there be no interpreter, let him keep silence in the church; and let him speak to himself, and to God."'),
('1 Corinthians', 14, 'teens', 3, 'How many people should speak in tongues at a gathering, and how?', 'At most two or three, and by course (taking turns), with an interpreter', 'As many as want, all at once', 'Everyone must speak in tongues', 'Only the pastor may speak in tongues', 'a', '1 Corinthians 14:27 — "If any man speak in an unknown tongue, let it be by two, or at the most by three, and that by course; and let one interpret."'),
('1 Corinthians', 14, 'teens', 4, 'What does Paul say about understanding in worship?', 'He wants to pray and sing with both the spirit and the understanding — using the mind as well as the spirit', 'Understanding does not matter in worship', 'Only feelings matter', 'The mind should be turned off during worship', 'a', '1 Corinthians 14:15 — "I will pray with the spirit, and I will pray with the understanding also: I will sing with the spirit, and I will sing with the understanding also."'),
('1 Corinthians', 14, 'teens', 5, 'What would an unbeliever think if everyone was speaking in tongues at once?', 'They would think the church members were mad (insane)', 'They would be deeply impressed', 'They would immediately convert', 'They would feel welcome', 'a', '1 Corinthians 14:23 — "If therefore the whole church be come together into one place, and all speak with tongues, and there come in those that are unlearned, or unbelievers, will they not say that ye are mad?"'),
-- Adults
('1 Corinthians', 14, 'adults', 1, 'How does Paul define prophecy''s threefold function?', 'Edification (building up), exhortation (urging action), and comfort (consolation) — prophecy addresses the congregation intelligibly for their spiritual benefit', 'Prediction of future events exclusively', 'Political commentary', 'Entertainment and spectacle', 'a', '1 Corinthians 14:3 — "But he that prophesieth speaketh unto men to edification, and exhortation, and comfort." New Testament prophecy is primarily forth-telling (speaking God''s truth to the congregation) rather than exclusively fore-telling.'),
('1 Corinthians', 14, 'adults', 2, 'What does Paul''s statement "I thank my God, I speak with tongues more than ye all" accomplish rhetorically?', 'It establishes Paul''s credibility on the topic — he cannot be accused of opposing tongues from ignorance or jealousy — before he then subordinates tongues to prophecy in the assembly', 'He is boasting about his superiority', 'He is exaggerating', 'He is being sarcastic', 'a', '1 Corinthians 14:18-19 — "I thank my God, I speak with tongues more than ye all: Yet in the church I had rather speak five words with my understanding, that by my voice I might teach others also, than ten thousand words in an unknown tongue."'),
('1 Corinthians', 14, 'adults', 3, 'What Old Testament text does Paul cite regarding tongues, and how does he apply it?', 'Isaiah 28:11-12 — God spoke to Israel through foreign-sounding languages (Assyrian invaders) as a sign of judgment; tongues similarly function as a sign for unbelievers, not for believers', 'Psalm 150 about praise instruments', 'Genesis 11 about the Tower of Babel', 'Exodus 4 about Moses'' speech difficulty', 'a', '1 Corinthians 14:21 — "In the law it is written, With men of other tongues and other lips will I speak unto this people; and yet for all that will they not hear me, saith the Lord" (Isaiah 28:11-12). Paul applies this to show tongues are a sign of judgment toward unbelievers.'),
('1 Corinthians', 14, 'adults', 4, 'What regulations does Paul establish for orderly worship?', 'Tongues: two or three speakers maximum, in turn, with interpretation required. Prophecy: two or three speakers, with others judging (evaluating). If no interpreter, the tongue-speaker must be silent. All in order', 'No regulations are needed — the Spirit will direct', 'Only one person may ever speak', 'Services should be completely spontaneous', 'a', '1 Corinthians 14:27-33 — Paul provides specific regulations: tongues (2-3, by course, with interpretation), prophecy (2-3, with evaluation), and the overarching principle that "God is not the author of confusion, but of peace" (v.33).'),
('1 Corinthians', 14, 'adults', 5, 'What is the effect of prophecy on an unbeliever entering the assembly?', 'The secrets of his heart are made manifest — he is convicted, judged, and falls down to worship God, declaring "God is in you of a truth"', 'He would be impressed by the spectacle', 'He would leave immediately', 'Nothing would happen', 'a', '1 Corinthians 14:24-25 — "But if all prophesy, and there come in one that believeth not... he is convinced of all, he is judged of all: And thus are the secrets of his heart made manifest; and so falling down on his face he will worship God, and report that God is in you of a truth."'),
('1 Corinthians', 14, 'adults', 6, 'What does "the spirits of the prophets are subject to the prophets" mean?', 'Prophetic utterance is under the speaker''s voluntary control — genuine inspiration does not produce ecstatic frenzy; a prophet can choose when to speak or be silent, maintaining order', 'Prophets cannot control when they speak', 'The Spirit forces uncontrollable utterances', 'Only false prophets maintain control', 'a', '1 Corinthians 14:32 — "And the spirits of the prophets are subject to the prophets." This distinguishes Christian prophecy from pagan ecstatic frenzy (manticism) where the speaker lost self-control. The Holy Spirit works with, not against, human volition.'),
('1 Corinthians', 14, 'adults', 7, 'How does Paul''s principle "let all things be done decently and in order" relate to Corinthian worship problems?', 'The Corinthians'' worship was chaotic — multiple tongue-speakers at once, no interpretation, everyone vying to participate simultaneously — Paul corrects this with the principle that divine worship should reflect God''s character of order and peace', 'Corinthian worship was already perfectly ordered', 'Paul is being overly controlling', 'Order is the opposite of spiritual freedom', 'a', '1 Corinthians 14:40 — "Let all things be done decently and in order." The Greek euschēmonōs kai kata taxin means "with propriety and according to arrangement." This is Paul''s final summary of the worship regulations in chapter 14.'),
('1 Corinthians', 14, 'adults', 8, 'What does Paul mean by "Be not children in understanding: howbeit in malice be ye children, but in understanding be men"?', 'The Corinthians were being childish in their pursuit of spectacular gifts like tongues — Paul urges them to be mature in their theological understanding while maintaining childlike innocence regarding evil', 'He wants them to be literally childish', 'He is against all forms of maturity', 'He wants them to be malicious adults', 'a', '1 Corinthians 14:20 — "Brethren, be not children in understanding: howbeit in malice be ye children, but in understanding be men." Paul calls for intellectual and spiritual maturity in evaluating gifts, combined with moral innocence.');

-- ═══ 1 Corinthians Chapter 15 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Corinthians', 15, 'kids', 1, 'Did Jesus rise from the dead?', 'Yes! Christ died for our sins, was buried, and rose again the third day', 'No one knows for sure', 'Only His spirit rose', 'He did not really die', 'a', '1 Corinthians 15:3-4 — "Christ died for our sins according to the scriptures; And that he was buried, and that he rose again the third day according to the scriptures."'),
('1 Corinthians', 15, 'kids', 2, 'Will believers also be raised from the dead?', 'Yes, because Jesus rose, all who believe in Him will be raised too', 'No, only Jesus rose', 'Only special people will rise', 'The Bible does not say', 'a', '1 Corinthians 15:20-22 — "But now is Christ risen from the dead, and become the firstfruits of them that slept... even so in Christ shall all be made alive."'),
('1 Corinthians', 15, 'kids', 3, 'What will happen to death in the end?', 'Death will be swallowed up in victory — it will be completely defeated', 'Death will last forever', 'Death cannot be defeated', 'Death will grow stronger', 'a', '1 Corinthians 15:54 — "Death is swallowed up in victory."'),
-- Teens
('1 Corinthians', 15, 'teens', 1, 'Who are some of the people who saw Jesus after He rose?', 'Cephas (Peter), then the twelve, then over 500 brethren at once, then James, then all the apostles, and lastly Paul himself', 'Only Mary Magdalene', 'No one saw Him after the resurrection', 'Only one or two people', 'a', '1 Corinthians 15:5-8 — "He was seen of Cephas, then of the twelve: After that, he was seen of above five hundred brethren at once... After that, he was seen of James; then of all the apostles. And last of all he was seen of me also."'),
('1 Corinthians', 15, 'teens', 2, 'If Christ is not risen, what does Paul say about the Christian faith?', 'Our faith is vain (empty), we are still in our sins, and we are of all men most miserable', 'Our faith is still perfectly fine', 'It does not matter whether He rose', 'We can believe whatever we want', 'a', '1 Corinthians 15:14,17,19 — "If Christ be not risen, then is our preaching vain, and your faith is also vain... ye are yet in your sins... we are of all men most miserable."'),
('1 Corinthians', 15, 'teens', 3, 'What is the last enemy that will be destroyed?', 'Death', 'Satan', 'Sin', 'Sickness', 'a', '1 Corinthians 15:26 — "The last enemy that shall be destroyed is death."'),
('1 Corinthians', 15, 'teens', 4, 'How does Paul describe the resurrection body compared to our current body?', 'Our current body is sown in corruption, dishonour, and weakness; it is raised in incorruption, glory, and power — a natural body is sown, a spiritual body is raised', 'The resurrection body is exactly the same', 'We will not have bodies at all', 'Our bodies will be weaker', 'a', '1 Corinthians 15:42-44 — "It is sown in corruption; it is raised in incorruption: It is sown in dishonour; it is raised in glory: it is sown in weakness; it is raised in power: It is sown a natural body; it is raised a spiritual body."'),
('1 Corinthians', 15, 'teens', 5, 'What triumphant words does Paul write about death at the end of the chapter?', '"O death, where is thy sting? O grave, where is thy victory?" — the sting of death is sin, and the strength of sin is the law, but thanks be to God who gives us victory through Jesus Christ', 'Death remains victorious', 'The grave has the final word', 'There is no hope against death', 'a', '1 Corinthians 15:55-57 — "O death, where is thy sting? O grave, where is thy victory? The sting of death is sin; and the strength of sin is the law. But thanks be to God, which giveth us the victory through our Lord Jesus Christ."'),
-- Adults
('1 Corinthians', 15, 'adults', 1, 'What creedal formula does Paul cite in verses 3-5, and why is it significant?', '"Christ died for our sins according to the scriptures, was buried, rose again the third day according to the scriptures, and was seen" — this is a pre-Pauline creed dating to within years of the crucifixion, demonstrating very early belief in the resurrection', 'Paul created this formula himself', 'It was composed in the second century', 'It is a later addition to the text', 'a', '1 Corinthians 15:3-5 — "For I delivered unto you first of all that which I also received." The verbs "received/delivered" (paralambano/paradidomi) are technical terms for transmitting authoritative tradition, indicating this is pre-Pauline creedal material.'),
('1 Corinthians', 15, 'adults', 2, 'What does "firstfruits" (aparchē) mean when applied to Christ''s resurrection?', 'Christ''s resurrection is the initial harvest guaranteeing the full harvest — just as the firstfruits offered in the temple represented and guaranteed the entire crop, Christ''s rising guarantees believers'' future resurrection', 'Christ was the first person ever to die', 'It refers to agricultural practices only', 'It means Christ''s resurrection was incomplete', 'a', '1 Corinthians 15:20,23 — "But now is Christ risen from the dead, and become the firstfruits of them that slept... Christ the firstfruits; afterward they that are Christ''s at his coming." The Feast of Firstfruits (Leviticus 23:10) typologically pictures Christ''s resurrection.'),
('1 Corinthians', 15, 'adults', 3, 'How does Paul''s Adam-Christ typology work in verses 21-22 and 45-49?', 'The first Adam brought death to all through sin; the last Adam (Christ) brings resurrection life to all who are in Him. The first Adam was a living soul from the earth; the last Adam is a life-giving spirit from heaven — believers will bear the image of the heavenly', 'Adam and Christ are the same person', 'The comparison is purely metaphorical', 'Paul invents this parallel with no OT basis', 'a', '1 Corinthians 15:21-22,45 — "For since by man came death, by man came also the resurrection of the dead... The first man Adam was made a living soul; the last Adam was made a quickening spirit." This is a federal headship argument — humanity''s destiny is determined by its representative head.'),
('1 Corinthians', 15, 'adults', 4, 'What does Paul teach about the nature of the resurrection body?', 'It is continuous with yet transformed from the present body — sown/raised contrasts (corruption/incorruption, dishonour/glory, weakness/power, natural/spiritual) show both continuity (same body sown and raised) and radical transformation', 'It is an entirely new body unrelated to the old', 'Resurrection is purely spiritual with no body', 'The resurrection body is identical to the current one', 'a', '1 Corinthians 15:42-44 — The seed analogy (vv.36-38) establishes continuity (the same seed that is planted grows), while the contrasts establish transformation. The resurrection body is the present body glorified, not a replacement.'),
('1 Corinthians', 15, 'adults', 5, 'What "mystery" does Paul reveal in verses 51-52?', '"We shall not all sleep, but we shall all be changed, in a moment, in the twinkling of an eye, at the last trump" — living believers at Christ''s return will be instantaneously transformed without dying', 'All believers must die before being resurrected', 'The mystery is that resurrection will not happen', 'Only the dead will be changed', 'a', '1 Corinthians 15:51-52 — "Behold, I shew you a mystery; We shall not all sleep, but we shall all be changed, In a moment, in the twinkling of an eye, at the last trump: for the trumpet shall sound, and the dead shall be raised incorruptible, and we shall be changed."'),
('1 Corinthians', 15, 'adults', 6, 'How does Paul''s argument "if the dead rise not... let us eat and drink; for to morrow we die" function?', 'It is a reductio ad absurdum — if there is no resurrection, then Christian morality, sacrifice, and suffering are pointless, and hedonism (quoting Isaiah 22:13) is the only logical response; but since this conclusion is absurd, the premise (no resurrection) must be false', 'Paul is recommending hedonism', 'He is quoting Greek philosophy approvingly', 'He genuinely doubts the resurrection', 'a', '1 Corinthians 15:32 — "If after the manner of men I have fought with beasts at Ephesus, what advantageth it me, if the dead rise not? let us eat and drink; for to morrow we die." Paul shows the existential absurdity of denying resurrection.'),
('1 Corinthians', 15, 'adults', 7, 'What does "flesh and blood cannot inherit the kingdom of God" mean?', 'The present mortal, perishable body in its current state is unsuited for the eternal kingdom — transformation (not destruction) is required; the body must be clothed with incorruption and immortality', 'Physical matter is inherently evil', 'Bodies will be abolished entirely', 'Only spirits enter heaven', 'a', '1 Corinthians 15:50 — "Now this I say, brethren, that flesh and blood cannot inherit the kingdom of God; neither doth corruption inherit incorruption." "Flesh and blood" is a Semitic idiom for mortal human nature, not a statement against materiality per se.'),
('1 Corinthians', 15, 'adults', 8, 'What does "then cometh the end, when he shall have delivered up the kingdom to God, even the Father" reveal about eschatology?', 'Christ''s mediatorial kingdom culminates when all enemies (including death) are subdued; He then delivers the kingdom to the Father and subjects Himself, so that "God may be all in all" — the Son''s voluntary submission preserves Trinitarian unity', 'Christ''s kingdom replaces the Father''s', 'The Son ceases to exist', 'The kingdom has no end', 'a', '1 Corinthians 15:24,28 — "Then cometh the end, when he shall have delivered up the kingdom to God, even the Father... then shall the Son also himself be subject unto him that put all things under him, that God may be all in all."');

-- ═══ 1 Corinthians Chapter 16 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Corinthians', 16, 'kids', 1, 'What did Paul ask the Corinthians to collect for?', 'A collection for the poor saints in Jerusalem', 'A collection for building a palace', 'Money for a new chariot', 'Gold for a statue', 'a', '1 Corinthians 16:1 — "Now concerning the collection for the saints, as I have given order to the churches of Galatia, even so do ye."'),
('1 Corinthians', 16, 'kids', 2, 'When did Paul say they should set aside their giving?', 'On the first day of the week', 'On the last day of the month', 'Only once a year', 'Whenever they felt like it', 'a', '1 Corinthians 16:2 — "Upon the first day of the week let every one of you lay by him in store, as God hath prospered him."'),
('1 Corinthians', 16, 'kids', 3, 'What does Paul tell them to do at the very end of the letter?', '"Watch ye, stand fast in the faith, quit you like men, be strong. Let all your things be done with charity (love)"', 'Be afraid and hide', 'Give up when things get hard', 'Do not talk to anyone', 'a', '1 Corinthians 16:13-14 — "Watch ye, stand fast in the faith, quit you like men, be strong. Let all your things be done with charity."'),
-- Teens
('1 Corinthians', 16, 'teens', 1, 'How should each person decide how much to give?', 'As God has prospered him — proportional giving based on what God has provided', 'A fixed amount for everyone', 'Nothing unless they are wealthy', 'Only what they can spare after all expenses', 'a', '1 Corinthians 16:2 — "Upon the first day of the week let every one of you lay by him in store, as God hath prospered him, that there be no gatherings when I come."'),
('1 Corinthians', 16, 'teens', 2, 'How did Paul want them to treat Timothy when he visited?', 'See that he is with you without fear and do not despise him — for he does the work of the Lord as Paul does', 'Ignore him completely', 'Test him harshly', 'Send him away', 'a', '1 Corinthians 16:10-11 — "Now if Timotheus come, see that he may be with you without fear: for he worketh the work of the Lord, as I also do. Let no man therefore despise him."'),
('1 Corinthians', 16, 'teens', 3, 'What did Paul say about Apollos visiting Corinth?', 'Paul greatly desired Apollos to come, but Apollos was not willing to come at that time — he would come when he had a convenient time', 'Apollos refused to ever visit Corinth', 'Paul forbade Apollos from going', 'Apollos was already there', 'a', '1 Corinthians 16:12 — "As touching our brother Apollos, I greatly desired him to come unto you with the brethren: but his will was not at all to come at this time; but he will come when he shall have convenient time."'),
('1 Corinthians', 16, 'teens', 4, 'What household does Paul commend for their service?', 'The household of Stephanas — they were the firstfruits of Achaia and had devoted themselves to the ministry of the saints', 'The household of Caesar', 'The household of Herod', 'The household of Pilate', 'a', '1 Corinthians 16:15 — "I beseech you, brethren, (ye know the house of Stephanas, that it is the firstfruits of Achaia, and that they have addicted themselves to the ministry of the saints)."'),
('1 Corinthians', 16, 'teens', 5, 'What Aramaic word does Paul use near the end of the letter?', 'Maranatha — meaning "Our Lord, come!" or "The Lord is coming"', 'Hallelujah', 'Amen', 'Hosanna', 'a', '1 Corinthians 16:22 — "If any man love not the Lord Jesus Christ, let him be Anathema Maranatha." Maranatha is an Aramaic word meaning "Our Lord, come!" — an early Christian prayer for Christ''s return.'),
-- Adults
('1 Corinthians', 16, 'adults', 1, 'What does Paul''s instruction about the collection reveal about early church practice?', 'Weekly, proportional, systematic giving on the first day of the week (Sunday) — indicating that Christians already gathered for worship on Sundays and that financial generosity was organised, not haphazard', 'Giving was completely spontaneous', 'Collections only happened once', 'Sunday worship had not yet begun', 'a', '1 Corinthians 16:1-2 — "Upon the first day of the week let every one of you lay by him in store, as God hath prospered him." This is early evidence for Sunday as the Christian day of assembly (cf. Acts 20:7, Revelation 1:10).'),
('1 Corinthians', 16, 'adults', 2, 'What does Paul''s reference to "a great door and effectual is opened unto me, and there are many adversaries" reveal about his ministry philosophy?', 'Effective ministry and opposition go hand in hand — Paul sees open doors and adversaries as simultaneous, not contradictory; opposition is not a reason to leave but rather confirms that significant work is happening', 'Opposition means God has closed the door', 'Paul is complaining about his difficulties', 'He plans to avoid all opposition', 'a', '1 Corinthians 16:9 — "For a great door and effectual is opened unto me, and there are many adversaries." Paul was in Ephesus during this time (cf. Acts 19), where he experienced both tremendous gospel advance and intense opposition.'),
('1 Corinthians', 16, 'adults', 3, 'What does the phrase "If any man love not the Lord Jesus Christ, let him be Anathema Maranatha" combine?', 'A solemn curse (anathema — devoted to destruction/excommunication) with an eschatological prayer (Maranatha — "Our Lord, come!") — invoking divine judgment on those who do not love Christ while simultaneously praying for His return', 'A simple farewell greeting', 'A blessing for everyone', 'A request for more donations', 'a', '1 Corinthians 16:22 — "Anathema" is a Greek term for a curse of separation (cf. Romans 9:3; Galatians 1:8-9), while "Maranatha" is Aramaic — the juxtaposition of Greek curse and Aramaic prayer reflects the bilingual early church and its apocalyptic expectation.'),
('1 Corinthians', 16, 'adults', 4, 'What does Paul''s commendation of Stephanas''s household as "firstfruits of Achaia" reveal?', 'They were the first converts in the province of Achaia (southern Greece) — Paul uses agricultural firstfruits language (cf. Romans 16:5) to denote both chronological priority and representative significance', 'They were the wealthiest family', 'They produced the best crops', 'They arrived in Corinth first', 'a', '1 Corinthians 16:15 — "Ye know the house of Stephanas, that it is the firstfruits of Achaia." Note that in Acts 17:34, Dionysius and Damaris believed in Athens (also in Achaia), but Stephanas was likely converted during Paul''s earlier visit to Corinth (Acts 18:1-11).'),
('1 Corinthians', 16, 'adults', 5, 'What does Paul''s statement about Apollos — "his will was not at all to come at this time" — reveal about apostolic relationships?', 'Apollos exercised independent judgment about his travel plans despite Paul''s strong desire — showing that early church leaders were colleagues, not subordinates under a papal hierarchy; Apollos had genuine autonomy', 'Paul controlled Apollos''s schedule', 'Apollos was rebelling against Paul', 'They were enemies', 'a', '1 Corinthians 16:12 — "As touching our brother Apollos, I greatly desired him to come unto you with the brethren: but his will was not at all to come at this time." The Greek thelēma (will/desire) is emphatic — Apollos made his own decision, and Paul respected it.'),
('1 Corinthians', 16, 'adults', 6, 'How do the five rapid imperatives in verses 13-14 function as a summary of the letter?', '"Watch" (against doctrinal error — ch.15), "stand fast in the faith" (against division — ch.1-4), "quit you like men" (against moral cowardice — ch.5-6), "be strong" (against self-indulgence — ch.8-10), "let all things be done with charity" (the governing principle — ch.13)', 'They are random military commands', 'They have no connection to the letter', 'They are borrowed from Roman military manuals', 'a', '1 Corinthians 16:13-14 — These five imperatives compress the entire letter''s concerns into a memorable charge. "Quit you like men" (andrizesthe) means "act courageously/maturely" — the same call to maturity found throughout the letter.'),
('1 Corinthians', 16, 'adults', 7, 'What is the significance of Paul writing the final greeting "with mine own hand"?', 'Paul typically dictated his letters through an amanuensis (secretary) but wrote the final greeting personally as authentication — proving the letter''s genuineness and adding a personal touch (cf. Galatians 6:11, Colossians 4:18, 2 Thessalonians 3:17)', 'He could not afford a secretary', 'The rest of the letter was not his', 'He was testing a new pen', 'a', '1 Corinthians 16:21 — "The salutation of me Paul with mine own hand." This autographic practice was common in ancient letter-writing as a seal of authenticity, confirming that the dictated content was genuinely from the named author.'),
('1 Corinthians', 16, 'adults', 8, 'How does 1 Corinthians 16 balance practical instructions with theological depth?', 'Paul seamlessly weaves mundane logistics (travel plans, collections, household greetings) with profound theological content (anathema/Maranatha, standing in the faith, love as governing principle) — showing that practical church life and deep theology are inseparable', 'The chapter is purely practical with no theology', 'It is purely theological with no practical content', 'It contradicts the rest of the letter', 'a', '1 Corinthians 16 integrates Paul''s travel plans (vv.5-9), personnel matters (vv.10-12,15-18), theological charge (vv.13-14), solemn warning (v.22), and personal greeting (vv.19-24) — modelling how gospel truth shapes every dimension of church life.');
